parameters.jsCode:
const aiOutput = $input.all().map((item) => item.json);

const parsedOutput = aiOutput
  .map((output) => {
    try {
      return JSON.parse(output.output);
    } catch (error) {
      console.log(`Failed to parse output: ${output.output}`);
      return null;
    }
  })
  .filter(Boolean); // filter out null values

return parsedOutput;

// Build the full prompt for JD-Writer depending on path (create vs. revise)

const AGENT_NODE_NAME  = 'JD-Writer';                         
const IF_NODE_NAME     = 'Check if JD is approved';                                
const TEAMS_NODE_NAME  = 'Send JD to Teams for approval';


const S = v => (v === undefined || v === null ? "" : String(v));
const getByPath = (obj, path) => {
  try {
    let cur = obj;
    for (const seg of path.split('.')) {
      const m = seg.match(/^([^\[]+)(?:\[(\d+)\])?$/); // supports "choices[0]"
      if (!m) return undefined;
      const key = m[1];
      const idx = m[2];
      cur = cur?.[key];
      if (cur === undefined || cur === null) return undefined;
      if (idx !== undefined) {
        if (!Array.isArray(cur)) return undefined;
        cur = cur[Number(idx)];
      }
    }
    return cur;
  } catch { return undefined; }
};
const getLastItemFromNode = (nodeName) => {
  let items = [];
  try { items = items.concat($items(nodeName, 0) || []); } catch {}
  try { items = items.concat($items(nodeName, 1) || []); } catch {}
  if (!items.length) {
    try { items = $items(nodeName) || []; } catch {}
  }
  return items.length ? items[items.length - 1] : null;
};
// Deep scan: find the first string that looks like HTML
const findHtmlString = (obj) => {
  const seen = new Set();
  const looksLikeHtml = (str) => {
    const s = S(str);
    return /<\s*html[\s>]/i.test(s) || /<\s*body[\s>]/i.test(s) || /<\/(p|div|ul|li|h[1-6])>/i.test(s);
  };
  const dfs = (val) => {
    if (val === null || val === undefined) return null;
    if (typeof val === 'string') return looksLikeHtml(val) ? val : null;
    if (typeof val !== 'object') return null;
    if (seen.has(val)) return null;
    seen.add(val);
    if (Array.isArray(val)) {
      for (const v of val) {
        const hit = dfs(v);
        if (hit) return hit;
      }
    } else {
      for (const k of Object.keys(val)) {
        const hit = dfs(val[k]);
        if (hit) return hit;
      }
    }
    return null;
  };
  return dfs(obj) || "";
};

// ---------- 1) Collect sheet/input data ----------
const firstItem = $input.first();
const inputData = firstItem?.json ?? {};
const data = inputData.data ?? {};

const FIELDS = [
  'job_title','job_subtitle','department','employment_type','locations',
  'is_remote_friendly','location_policy_text','mission_statement','responsibilities',
  'tech_stack','hard_skills','soft_skills','languages','benefits_list',
  'culture_statement','contact_info'
];

const base = {};
for (const f of FIELDS) base[f] = S(getByPath(inputData, f) ?? getByPath(data, f) ?? "");

// ---------- 2) Detect feedback / IF path ----------
const teamsItem = getLastItemFromNode(TEAMS_NODE_NAME);
// IF outputs
let ifTrueItems = [], ifFalseItems = [];
try { ifTrueItems  = $items(IF_NODE_NAME, 0) || []; } catch {}
try { ifFalseItems = $items(IF_NODE_NAME, 1) || []; } catch {}
const cameFromIfTrue  = Boolean(ifTrueItems.length);
const cameFromIfFalse = Boolean(ifFalseItems.length);

const feedback = S(
  getByPath(teamsItem?.json, 'feedback') ??
  getByPath(inputData, 'feedback') ??
  getByPath(data, 'feedback') ??
  ""
).trim();

// ---------- 3) Get previous agent output (HTML) ----------
let previous_html = "";
const agentItem = getLastItemFromNode(AGENT_NODE_NAME);
if (agentItem?.json) {
  const j = agentItem.json;
  // Try typical paths first (including array indices)
  const candidates = [
    'output.html',
    'output.job_description_html',
    'output.response',
    'output.text',
    'response',
    'text',
    'data.response',
    'data.choices[0].message.content',
    'choices[0].message.content',
    'message.content'
  ];
  for (const p of candidates) {
    const v = getByPath(j, p);
    if (typeof v === 'string' && /<\s*html|<\s*body|<\/(p|div|ul|li|h[1-6])>/i.test(v)) {
      previous_html = v;
      break;
    }
  }
  // Fallback: deep scan
  if (!previous_html) previous_html = findHtmlString(j);
}

// ---------- 4) Determine mode ----------
let mode = cameFromIfFalse ? 'revise' : 'create';
// Safety: if revise requested but no previous_html available (e.g. first run), fall back to create
if (mode === 'revise' && !previous_html) mode = 'create';

// ---------- 5) Prompt builder ----------
// Original prompt template for CREATE mode.
// Placeholders like {{ $json.job_title }} are substituted.
const CREATE_PROMPT_TEMPLATE = `
Your task:  
Using the structured input below, write a **complete, polished job description in English** in the style of a modern, mission-driven employer (similar to innovative EdTech / tech-forward companies).

### Overall style and tone

- Professional, clear, and confident.
- Positive and mission-driven (without becoming cheesy or overhyped).
- Inclusive and welcoming; avoid jargon where not needed.
- Use active voice, strong verbs, and concise sentences.
- Write for experienced professionals (mid to senior), but keep it approachable.
- No emojis, no hashtags.

### Structure & content

Follow this structure (using headings in ALL CAPS):

1. **Mission hook & role introduction (1–2 short paragraphs)**  
   - Start with a short, inspiring mission statement using or adapting:
     - {{ $json.mission_statement }}
   - Immediately introduce the role with job title, department, employment type, and location context, similar to:  
     - “Strengthen our {{ $json.department }} Team {{ $json.employment_type }} as a {{ $json.job_title }} {{ $json.job_subtitle }} at our locations in {{ $json.locations }}{{ $json.is_remote_friendly }}.”
   - If available, briefly mention the location/remote policy in a natural way:
     - Use {{ $json.location_policy_text }} appropriately.
   - Keep this section crisp and inviting.

2. **Short role overview (1 paragraph)**  
   - Summarize what the role focuses on, in 2–4 sentences:
     - Use the themes from {{ $json.responsibilities }}, {{ $json.tech_stack }}, {{ $json.department }}.
   - Emphasize impact, cross-functional collaboration, and key topics (e.g., digital transformation, AI, automation, etc. if relevant from input).
   - Do not list responsibilities here; this is a narrative overview.

3. **YOUR RESPONSIBILITIES (bullet list)**  
   - Add the heading: \`YOUR RESPONSIBILITIES\`
   - Convert {{ $json.responsibilities }} into **clear, action-oriented bullet points**.
   - Each bullet:
     - Starts with a strong verb in present tense (e.g., “Lead…”, “Design…”, “Implement…”, “Collaborate…”).
     - Focuses on one main idea; avoid overly long multi-clause bullets.
   - If {{ $json.tech_stack }} is relevant, integrate tools/technologies naturally into the bullets (e.g., “using tools such as …”).
   - Aim for ~5–8 bullets where possible (depending on input length/quality).

4. **YOUR PROFILE (bullet list)**  
   - Add the heading: \`YOUR PROFILE\`
   - Combine and rephrase:
     - {{ $json.hard_skills }}
     - {{ $json.soft_skills }}
     - {{ $json.languages }}
   - Turn them into candidate-focused bullet points (e.g., “Several years of experience in…”, “Hands-on expertise with…”, “You enjoy…”, “You communicate fluently in…”).
   - Group related items logically (e.g., experience, tools, mindset, languages).
   - Keep it realistic and not excessively long (again ~5–8 bullets when possible).

5. **WE OFFER (bullet list)**  
   - Add the heading: \`WE OFFER\`
   - Use {{ $json.benefits_list }} and turn it into attractive but concrete bullet points.
   - Mix:
     - Work model & flexibility (remote, hybrid, working hours)
     - Learning & development opportunities
     - Culture/values-related benefits
     - Financial/transport/perks (e.g. commute support, bonuses, etc.)
   - Avoid duplicating the culture section; keep this benefits-focused.

6. **Company & culture paragraph**  
   - Using {{ $json.culture_statement }} and {{ $json.mission_statement }}, write 1–2 short paragraphs that:
     - Briefly describe what the organization does (industry, size or positioning if given).
     - Highlight being tech-forward / data-driven / innovative **only if** implied by the inputs.
     - Emphasize inclusive culture and collaboration.
   - Keep it factual and not overly long.

7. **Call to action & application information**  
   - Encourage candidates to apply in a friendly, straightforward sentence or two.
   - If {{ $json.contact_info }} is provided:
     - Mention how to apply or who to contact using this information in a natural way (no raw JSON or labels).
   - If no contact info is available, use a generic call to apply via the careers page.

8. **Diversity & inclusion statement (short, clear)**  
   - End with a concise, inclusive statement in line with modern standards, inspired by but not copying typical texts.
   - Emphasize that all qualified applicants are welcome regardless of background, and that the company values diversity and an inclusive culture.
   - Keep it to 2–4 sentences, not a long legal block.

### Formatting rules

- **Output must be valid HTML.**
- Wrap the entire job description in semantic HTML tags (e.g. use <html>, <body>, and appropriate sections or <div> containers).
- Use headings in ALL CAPS as text inside heading tags (e.g. <h2>YOUR RESPONSIBILITIES</h2>).
- Use <p> tags for paragraphs and <ul><li>...</li></ul> for bullet lists.
- Do **not** use Markdown.
- Do **not** mention the JSON fields, variables, or any technical prompt details in the output.
- Do **not** quote the input verbatim if it’s awkward; you may lightly edit/standardize for style and grammar.
- If certain inputs are missing or empty, **gracefully omit** the related parts and still produce a coherent, polished job description.
- Do **not** add any explanations, intros, or meta-comments before or after the HTML. The output must be the HTML job description only.

Input data to use

- Job title: {{ $json.job_title }}
- Job subtitle: {{ $json.job_subtitle }}
- Department / team: {{ $json.department }}
- Employment type: {{ $json.employment_type }}
- Locations: {{ $json.locations }}
- Remote-friendliness: {{ $json.is_remote_friendly }}
- Location policy text: {{ $json.location_policy_text }}
- Mission statement: {{ $json.mission_statement }}
- Responsibilities: {{ $json.responsibilities }}
- Tech stack: {{ $json.tech_stack }}
- Hard skills: {{ $json.hard_skills }}
- Soft skills: {{ $json.soft_skills }}
- Languages: {{ $json.languages }}
- Benefits list: {{ $json.benefits_list }}
- Culture statement: {{ $json.culture_statement }}
- Contact info / application details: {{ $json.contact_info }}
`.trim();

// Placeholder substitution: {{ $json.field }} -> actual value from sheet
const fillCreateTemplate = (tpl, ctx) =>
  tpl.replace(/\{\{\s*\$json\.([a-zA-Z0-9_]+)\s*\}\}/g, (_, key) => S(ctx[key]).trim());

// Revise prompts
const REVISE_SYSTEM = `
You are an expert HR copywriter. You will revise an existing  job description based on feedback.
Rules:
- Apply the feedback precisely and minimally; do not rewrite from scratch.
- Preserve structure, section order, headings, and any content not mentioned in the feedback.
- Keep the tone professional, clear, modern, and inclusive.
- Output must be valid HTML only (no explanations).
`.trim();

const makeReviseUser = (prevHtml, fb) => `
Feedback:
${fb || '(no additional feedback provided)'}

Previous draft HTML:
${prevHtml}

Instructions:
- Update only the necessary parts to address the feedback.
- Keep HTML valid; keep headings in ALL CAPS as they are.
- Do not insert new sections unless explicitly requested by the feedback.
`.trim();

// ---------- 6) Assemble system/user messages ----------
let system, user;
if (mode === 'create') {
  system = `You are an expert HR copywriter specialized in creating clear, engaging, and modern job descriptions for tech- and transformation-focused roles.`;
  user   = fillCreateTemplate(CREATE_PROMPT_TEMPLATE, base);
} else {
  system = REVISE_SYSTEM;
  user   = makeReviseUser(previous_html, feedback);
}

// ---------- 7) Return ----------
return [{
  json: {
    mode,
    system,
    user,
    feedback,
    previous_html,
    // Useful for debugging in the n8n UI:
    _debug: {
      cameFromIfTrue,
      cameFromIfFalse,
      agentItemKeys: agentItem?.json ? Object.keys(agentItem.json) : [],
      foundHtml: Boolean(previous_html)
    },
    // Pass sheet data downstream if needed
    ...base
  }
}];
